var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"오늘은 건틀렛 보는 날.","JPN":"今日はガントレットを見る日。","ENG":"Today is Gauntlet day.","TWN":"今天是觀看聖鎧比賽的日子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"엄마랑 아빠는 더 큰 다음에 보라고 했지만 괜찮아.","JPN":"ママとパパはもっと大きくなってから見てねって言ったけど、大丈夫。","ENG":"Mom and Dad told me to watch when I'm older, but it's okay.","TWN":"爸爸媽媽叫我長大後再看，但是沒關係。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"엄마랑 아빠는 일 때문에 늦게 온다고 하셨으니까.","JPN":"ママとパパは仕事で遅くなるって言ったから。","ENG":"They said that they're going to be late tonight.","TWN":"他們說因為工作的關係會晚點回來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까 저건, 엄마가 아니야.","JPN":"だからあれは、ママじゃない。","ENG":"So that woman isn't my mother.","TWN":"所以，那個人不是媽媽。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>새로운 본선 진출 팀을 환영해 주시기 바랍니다! 카나리아 스쿼드!</color>","JPN":"<color=#ffd34c>新しく本選に進出したチームを歓迎してください！　カナリア・スクワッド！</color>","ENG":"<color=#ffd34c>Please welcome the newest team that made it to the elimination rounds! Canary Squad!</color>","TWN":"<color=#ffd34c>讓我們歡迎打入決賽的隊伍！金絲雀小隊！</color>"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"다들 고생했어!","JPN":"みんな、お疲れ様！","ENG":"Good work, everyone!","TWN":"大家都辛苦啦！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아…… 죽겠다. 일단 의무실부터 가야겠어.","JPN":"あ……死ぬ。とりあえず医務室から行こう。","ENG":"Gah... I'm this close from passing out. I need to go to the infirmary first.","TWN":"呃……我快死啦，我要先去醫務室。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도요. 온몸의 힘이 쭉 빠진 기분이에요…….","JPN":"私もです。全身の力が抜けちゃった気分ですよ……","ENG":"Me too. I feel as if all my energy has been drained...","TWN":"我也是，感覺筋疲力盡的……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치! 들었죠? 본선 진출이래요!","JPN":"コーチ！　聞きました？　本選進出ですって！","ENG":"Coach! Did you hear that? We made it to the elimination rounds!","TWN":"教練！你有聽到嗎？我們打入決賽了！"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"수고 많았네. 펠리세트.","JPN":"ご苦労様。フェリセット。","ENG":"Good work, Félicette.","TWN":"辛苦你囉，費莉塞特。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"샤레이드 건틀렛 리그에서 데뷔한 시즌에 본선 진출을 이룬 팀은 서른 개밖에 없어요.","JPN":"シャレードガントレットリーグで、デビューしたシーズンに本選進出に成功したチームは30チームしかありません。","ENG":"There are only thirty teams in Charade Gauntlet League history who made it to the elimination rounds on their debut season.","TWN":"在查雷德聖鎧聯賽的歷史上，只有三十支隊伍首次參賽就打進決賽。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희가 바로 그 서른 번째구요.","JPN":"私たちがその30番目です。","ENG":"We are the thirtieth.","TWN":"我們就是那第三十個。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"정말 대단한 성과예요. 어쩌면 어제 갔던 박물관에 기록될지도 모를 만큼.","JPN":"本当にすごい成果です。もしかしたら、昨日行った博物館に記録されるかもしれないほどに。","ENG":"This is amazing. We might be recorded in the museum that we went to yesterday.","TWN":"這真的很厲害，說不定會被我們昨天去過的博物館給記錄下來。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"그 정도인가?","JPN":"それほどなのか？","ENG":"Is it that impressive?","TWN":"有那麼厲害喔？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼요. 엔트리를 최소 조건만 만족한 상태로 이룬 결과니까 더 대단한 거예요.","JPN":"もちろんです。エントリーの最小条件だけを満たして成し遂げた結果ですから、もっとすごいんです。","ENG":"Of course it is. Especially since we've accomplished this with the minimum entry requirements.","TWN":"當然。而且我們還是在滿足最低人數條件下贏的，所以更厲害。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"암전 기믹 때 어땠는지 코치도 봤으면 좋았을 텐데.","JPN":"暗転ギミックの時にどうだったか、コーチも見れたらよかったのに。","ENG":"You should have seen what happened during the lights-out gimmick.","TWN":"真希望教練也能看到我們夜戰時的表現。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"평소에 꾸준히 훈련한 덕분에 린치에도 버텼거든요.","JPN":"普段こつこつと訓練したおかげで、リンチにも耐えられたんです。","ENG":"We were able to survive the lynching thanks to training.","TWN":"多虧平時有努力的訓練，我們才能堅持下來。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카 같은 게으름뱅이는 절대 못 버텼을 거예요.","JPN":"ライカみたいな怠け者には、絶対耐えられなかったはずです。","ENG":"A sloth like Laika would have never made it.","TWN":"要不然像萊卡那種懶惰蟲是絕對撐不住的。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 무사해서 다행일세.","JPN":"だが、無事で何よりだ。","ENG":"I'm just glad that you're all safe.","TWN":"不過幸好大家都沒事。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저랑 라이카만으로는 힘들었을 거예요.","JPN":"私とライカだけでは無理だったと思います。","ENG":"It would have been impossible with just me and Laika.","TWN":"當然光靠我和萊卡肯定做不到。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이번 경기……. 아니, 예선전 전부.","JPN":"この試合……いや、すべての予選が。","ENG":"This match... no, throughout the whole qualifiers.","TWN":"這次比賽……不，我是說，整個預賽。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치, 저번에 제가 만나고 싶은 사람이 있다고 했죠?","JPN":"コーチ、この前、会いたい人がいるって話しましたよね？","ENG":"Coach, do you remember when I said that there was someone that I wanted to meet?","TWN":"教練，上次我說過有個我想見的人吧？"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"본선 결승에 올라가면 말해 준다고 했지.","JPN":"本戦決勝に行けたら話してくれると言っていたな。","ENG":"You told me that you'll speak when we get to the finals.","TWN":"你還說進入決賽的話就告訴我。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……어쩌면 저도 결승에 올라갈 수 없다고 생각했는지도 몰라요.","JPN":"……もしかしたら、私も決勝には行けないと思っていたのかもしれません。","ENG":"...Perhaps I thought that we wouldn't be able to make it.","TWN":"……當時我或許也覺得進入決賽無望。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말할 생각이 없었으니까.","JPN":"話す気なんてなかったんですから。","ENG":"Because I had no intention of telling you.","TWN":"所以我根本沒打算說。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇지만 지금은 아니에요.","JPN":"でも、今は違います。","ENG":"But not anymore.","TWN":"但現在我改變想法了。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"팀원들에게…… 적어도 코치에게는 말해야 한다고 봐요.","JPN":"チームメンバーに……少なくとも、コーチには話すべきだと思います。","ENG":"I feel the need to tell everyone in the team... or, at the very least, to you.","TWN":"我應該要告訴隊員……或者至少告訴教練。"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제가 그 사람을 만나려는 이유는……","JPN":"私があの人に会おうとしてる理由は……","ENG":"The reason why I want to meet the person is...","TWN":"我之所以想見那個人……"},"stage":{"bg":"STADIUM","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"죽여 버리고 싶어서니까요.","JPN":"殺したいからです。","ENG":"Because I want to kill her.","TWN":"是因為我想殺了她。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};